#define NUM_MONSTERS 195

static unsigned s_seed = 12345;
static int _rng(int lo, int hi) {
    s_seed = s_seed * 1664525u + 1013904223u;
    if (hi <= lo) return lo;
    return lo + (int)((s_seed >> 16) % (unsigned)(hi - lo + 1));
}

void monster_rng_seed(unsigned seed) { s_seed = seed; }
int  monster_roll(int sides) { return (sides > 0) ? _rng(1, sides) : 0; }

const MonsterType *monster_get(int id) {
    if (id < 0 || id >= NUM_MONSTERS) return &s_monsters[0];
    return &s_monsters[id];
}

int monster_count(void) { return NUM_MONSTERS; }

int monster_sprite_id(int monster_index) {
    int n = (int)(sizeof(s_sprite_ids)/sizeof(s_sprite_ids[0]));
    if (monster_index < 0 || monster_index >= n) return 0;
    return s_sprite_ids[monster_index];
}

void encounter_generate(int max_level, int max_qty, MonsterGroup *out, int *out_count) {
    int pool[NUM_MONSTERS], n = 0;
    for (int i = 0; i < NUM_MONSTERS; i++)
        if (s_monsters[i].level <= max_level && s_monsters[i].level > 0) pool[n++] = i;
    if (n == 0) { *out_count = 0; return; }
    const MonsterType *mt = &s_monsters[pool[_rng(0, n-1)]];
    int cnt = _rng(1, mt->max_group < max_qty ? mt->max_group : max_qty);
    if (cnt < 1) cnt = 1;
    if (cnt > MAX_MONSTER_GROUP) cnt = MAX_MONSTER_GROUP;
    out->type = mt; out->count = cnt; out->alive = cnt; out->sleep_rounds = 0;
    for (int i = 0; i < cnt; i++) out->hp[i] = mt->hp > 0 ? mt->hp : 1;
    *out_count = 1;
}
